 {"id":"bd-k5q5.9.2.2","title":"[LISR-2.2] Implement tolerant AST recovery and ambiguity detection","description":"Add tolerant parsing/recovery for partially broken extensions and detect ambiguous constructs that reduce repair confidence.","design":"Track ambiguity classes (syntax fracture, unresolved symbol clusters, conflicting hook signatures) as first-class scoring inputs.","acceptance_criteria":"Recovery pipeline produces deterministic ambiguity metadata for identical inputs.","notes":"Without ambiguity detection, confidence scores are over-optimistic and unsafe.","status":"closed","priority":0,"issue_type":"task","created_at":"2026-02-08T21:32:33.803918588Z","created_by":"ubuntu","updated_at":"2026-02-08T23:07:52.242813119Z","closed_at":"2026-02-08T23:07:52.242717560Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["ast","extensions","intent","lisr","repair"],"dependencies":[{"issue_id":"bd-k5q5.9.2.2","depends_on_id":"bd-k5q5.9.2","type":"parent-child","created_at":"2026-02-08T21:32:33.803918588Z","created_by":"ubuntu"}]}
 {"id":"bd-k5q5.9.2.3","title":"[LISR-2.3] Implement confidence scoring model with explainable signals","description":"Compute legibility confidence using weighted deterministic signals and explicit penalties for ambiguity/risk indicators.","design":"Output score plus per-signal contributions so operators and tests can explain every gating outcome.","acceptance_criteria":"Confidence computation is deterministic, calibrated on fixtures, and stable across runs.","notes":"Explainability is mandatory for trust and policy review.","status":"closed","priority":0,"issue_type":"task","created_at":"2026-02-08T21:32:34.843263213Z","created_by":"ubuntu","updated_at":"2026-02-08T23:11:55.098723643Z","closed_at":"2026-02-08T23:11:55.098630059Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["extensions","intent","lisr","repair","scoring"],"dependencies":[{"issue_id":"bd-k5q5.9.2.3","depends_on_id":"bd-k5q5.9.2","type":"parent-child","created_at":"2026-02-08T21:32:34.843263213Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.2.3","depends_on_id":"bd-k5q5.9.2.1","type":"blocks","created_at":"2026-02-08T21:32:59.407851300Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.2.3","depends_on_id":"bd-k5q5.9.2.2","type":"blocks","created_at":"2026-02-08T21:32:59.690075239Z","created_by":"ubuntu"}]}
 {"id":"bd-k5q5.9.2.4","title":"[LISR-2.4] Implement gating decision API and reason-code contract","description":"Expose allow/suggest/deny gating API with structured reason codes and remediation guidance for denied cases.","design":"Integrate with policy modes so gate outcomes are actionable and composable with downstream repair strategy.","acceptance_criteria":"All non-allow decisions include machine-readable reasons, human-readable explanation, and suggested next steps.","notes":"This becomes the canonical control handoff from analysis to repair.","status":"closed","priority":0,"issue_type":"task","created_at":"2026-02-08T21:32:35.780726484Z","created_by":"ubuntu","updated_at":"2026-02-08T23:17:00.597666343Z","closed_at":"2026-02-08T23:17:00.597575734Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["extensions","gating","intent","lisr","repair"],"dependencies":[{"issue_id":"bd-k5q5.9.2.4","depends_on_id":"bd-k5q5.9.2","type":"parent-child","created_at":"2026-02-08T21:32:35.780726484Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.2.4","depends_on_id":"bd-k5q5.9.2.3","type":"blocks","created_at":"2026-02-08T21:32:59.983239760Z","created_by":"ubuntu"}]}
-{"id":"bd-k5q5.9.3","title":"[LISR-3] Deterministic Rule-First Repair Engine","description":"Implement deterministic rewrite rules for known breakage classes before considering model assistance.","design":"Use versioned rule registry and ordered application over AST/schema transforms; ensure repeatable output and minimal-diff selection.","acceptance_criteria":"Known migration and normalization failures are repaired by deterministic rules with reproducible output and test coverage.","notes":"Rule-first design gives us most value with least risk, and keeps AI usage optional rather than mandatory.","status":"open","priority":0,"issue_type":"epic","created_at":"2026-02-08T21:32:25.313377697Z","created_by":"ubuntu","updated_at":"2026-02-08T21:35:28.213976432Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["deterministic","extensions","lisr","repair","rules"],"dependencies":[{"issue_id":"bd-k5q5.9.3","depends_on_id":"bd-k5q5.9","type":"parent-child","created_at":"2026-02-08T21:32:25.313377697Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.3","depends_on_id":"bd-k5q5.9.1","type":"blocks","created_at":"2026-02-08T21:32:53.966653448Z","created_by":"ubuntu"}],"comments":[{"id":836,"issue_id":"bd-k5q5.9.3","author":"Dicklesworthstone","text":"Deterministic repairs are prioritized for predictable behavior, lower risk, and easier auditability compared to model-generated changes.","created_at":"2026-02-08T21:33:09Z"},{"id":848,"issue_id":"bd-k5q5.9.3","author":"Dicklesworthstone","text":"Dependency intent for LISR-3:\\n- 3.1 defines deterministic rule execution order and versioning.\\n- 3.2 and 3.3 implement high-value deterministic fix classes (manifest + AST migrations).\\n- 3.4 chooses the safest minimal candidate and resolves rule collisions.\\nThis keeps most repair traffic in deterministic, auditable paths.","created_at":"2026-02-08T21:34:44Z"},{"id":859,"issue_id":"bd-k5q5.9.3","author":"Dicklesworthstone","text":"LISR-3 sequencing note:\n- Registry first (ordering/versioning).\n- Rule packs second (manifest + AST).\n- Candidate minimization last to avoid over-editing.","created_at":"2026-02-08T21:35:28Z"}]}
+{"id":"bd-k5q5.9.3","title":"[LISR-3] Deterministic Rule-First Repair Engine","description":"Implement deterministic rewrite rules for known breakage classes before considering model assistance.","design":"Use versioned rule registry and ordered application over AST/schema transforms; ensure repeatable output and minimal-diff selection.","acceptance_criteria":"Known migration and normalization failures are repaired by deterministic rules with reproducible output and test coverage.","notes":"Rule-first design gives us most value with least risk, and keeps AI usage optional rather than mandatory.","status":"closed","priority":0,"issue_type":"epic","created_at":"2026-02-08T21:32:25.313377697Z","created_by":"ubuntu","updated_at":"2026-02-08T23:21:21.658544475Z","closed_at":"2026-02-08T23:21:21.658453746Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["deterministic","extensions","lisr","repair","rules"],"dependencies":[{"issue_id":"bd-k5q5.9.3","depends_on_id":"bd-k5q5.9","type":"parent-child","created_at":"2026-02-08T21:32:25.313377697Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.3","depends_on_id":"bd-k5q5.9.1","type":"blocks","created_at":"2026-02-08T21:32:53.966653448Z","created_by":"ubuntu"}],"comments":[{"id":836,"issue_id":"bd-k5q5.9.3","author":"Dicklesworthstone","text":"Deterministic repairs are prioritized for predictable behavior, lower risk, and easier auditability compared to model-generated changes.","created_at":"2026-02-08T21:33:09Z"},{"id":848,"issue_id":"bd-k5q5.9.3","author":"Dicklesworthstone","text":"Dependency intent for LISR-3:\\n- 3.1 defines deterministic rule execution order and versioning.\\n- 3.2 and 3.3 implement high-value deterministic fix classes (manifest + AST migrations).\\n- 3.4 chooses the safest minimal candidate and resolves rule collisions.\\nThis keeps most repair traffic in deterministic, auditable paths.","created_at":"2026-02-08T21:34:44Z"},{"id":859,"issue_id":"bd-k5q5.9.3","author":"Dicklesworthstone","text":"LISR-3 sequencing note:\n- Registry first (ordering/versioning).\n- Rule packs second (manifest + AST).\n- Candidate minimization last to avoid over-editing.","created_at":"2026-02-08T21:35:28Z"}]}
 {"id":"bd-k5q5.9.3.1","title":"[LISR-3.1] Implement versioned deterministic rule registry","description":"Create rule registry with explicit ordering, versioning, and applicability predicates for deterministic repairs.","design":"Rules must be discoverable, testable in isolation, and composable without nondeterministic side effects.","acceptance_criteria":"Registry supports deterministic replay and emits trace of applied/skipped rules.","notes":"A formal registry prevents ad hoc rewrites and keeps repair behavior auditable.","status":"closed","priority":0,"issue_type":"task","created_at":"2026-02-08T21:32:36.403030771Z","created_by":"ubuntu","updated_at":"2026-02-08T22:32:31.160283839Z","closed_at":"2026-02-08T22:32:31.160181087Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["extensions","lisr","registry","repair","rules"],"dependencies":[{"issue_id":"bd-k5q5.9.3.1","depends_on_id":"bd-k5q5.9.3","type":"parent-child","created_at":"2026-02-08T21:32:36.403030771Z","created_by":"ubuntu"}]}
 {"id":"bd-k5q5.9.3.2","title":"[LISR-3.2] Build manifest normalization and schema migration rules","description":"Implement deterministic fixes for manifest-level drift: schema version migration, field normalization, and deprecated key translation.","design":"Preserve semantic intent while enforcing canonical layout and validation compatibility.","acceptance_criteria":"Rule pack repairs known manifest failures and passes migration fixture suite.","notes":"Manifest errors are common and high-leverage for auto-healing wins.","status":"closed","priority":0,"issue_type":"task","created_at":"2026-02-08T21:32:37.003230608Z","created_by":"ubuntu","updated_at":"2026-02-08T22:42:07.317500971Z","closed_at":"2026-02-08T22:42:07.317411063Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["extensions","lisr","manifest","repair","rules"],"dependencies":[{"issue_id":"bd-k5q5.9.3.2","depends_on_id":"bd-k5q5.9.3","type":"parent-child","created_at":"2026-02-08T21:32:37.003230608Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.3.2","depends_on_id":"bd-k5q5.9.3.1","type":"blocks","created_at":"2026-02-08T21:33:00.245881988Z","created_by":"ubuntu"}]}
 {"id":"bd-k5q5.9.3.3","title":"[LISR-3.3] Build AST codemod rules for known API migrations","description":"Implement AST-based codemods for known extension API renames/signature migrations, avoiding regex rewrites.","design":"Codemods must preserve ordering and semantics where intended, with explicit unsupported-case handling.","acceptance_criteria":"Codemod pack passes fixture-based before/after snapshots and semantic sanity checks.","notes":"AST-level transforms reduce collateral damage and are safer than textual rewrites.","status":"closed","priority":0,"issue_type":"task","created_at":"2026-02-08T21:32:37.634972990Z","created_by":"ubuntu","updated_at":"2026-02-08T22:42:08.780455004Z","closed_at":"2026-02-08T22:42:08.780354787Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["codemod","extensions","lisr","repair","rules"],"dependencies":[{"issue_id":"bd-k5q5.9.3.3","depends_on_id":"bd-k5q5.9.3","type":"parent-child","created_at":"2026-02-08T21:32:37.634972990Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.3.3","depends_on_id":"bd-k5q5.9.3.1","type":"blocks","created_at":"2026-02-08T21:33:00.522252652Z","created_by":"ubuntu"}]}
-{"id":"bd-k5q5.9.3.4","title":"[LISR-3.4] Implement minimal-diff candidate selector and conflict resolver","description":"When multiple deterministic candidates exist, choose the minimal-risk minimal-diff repair and resolve rule conflicts deterministically.","design":"Introduce scoring based on diff size, affected sensitive surfaces, and confidence alignment.","acceptance_criteria":"Selector always returns deterministic winner or explicit no-safe-candidate result.","notes":"This avoids over-editing and keeps repairs constrained to necessary changes.","status":"open","priority":1,"issue_type":"task","created_at":"2026-02-08T21:32:38.254272971Z","created_by":"ubuntu","updated_at":"2026-02-08T21:33:01.080343146Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["extensions","lisr","repair","rules","selection"],"dependencies":[{"issue_id":"bd-k5q5.9.3.4","depends_on_id":"bd-k5q5.9.3","type":"parent-child","created_at":"2026-02-08T21:32:38.254272971Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.3.4","depends_on_id":"bd-k5q5.9.3.2","type":"blocks","created_at":"2026-02-08T21:33:00.797572018Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.3.4","depends_on_id":"bd-k5q5.9.3.3","type":"blocks","created_at":"2026-02-08T21:33:01.080281752Z","created_by":"ubuntu"}]}
-{"id":"bd-k5q5.9.4","title":"[LISR-4] Controlled Model-Assisted Repair (Whitelist Only)","description":"Add bounded model-assisted repair proposals for cases deterministic rules cannot resolve, while preserving strict policy controls.","design":"Model outputs are limited to validated primitive patch operations; all proposals are schema-validated and policy-checked before application.","acceptance_criteria":"Model-assisted path cannot bypass policy, cannot introduce unapproved capability expansion, and always emits explainable rejected/accepted decisions.","notes":"This gives coverage for long-tail failures without creating an unconstrained code-generation attack surface.","status":"open","priority":1,"issue_type":"epic","created_at":"2026-02-08T21:32:26.246357580Z","created_by":"ubuntu","updated_at":"2026-02-08T21:35:28.481439309Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["ai","extensions","guardrails","lisr","repair"],"dependencies":[{"issue_id":"bd-k5q5.9.4","depends_on_id":"bd-k5q5.9","type":"parent-child","created_at":"2026-02-08T21:32:26.246357580Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.4","depends_on_id":"bd-k5q5.9.1","type":"blocks","created_at":"2026-02-08T21:32:54.297119872Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.4","depends_on_id":"bd-k5q5.9.2","type":"blocks","created_at":"2026-02-08T21:32:55.890049829Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.4","depends_on_id":"bd-k5q5.9.3","type":"blocks","created_at":"2026-02-08T21:32:56.177134804Z","created_by":"ubuntu"}],"comments":[{"id":837,"issue_id":"bd-k5q5.9.4","author":"Dicklesworthstone","text":"Model assistance is scoped to structured primitives only; free-form code generation is explicitly excluded to preserve safety invariants.","created_at":"2026-02-08T21:33:09Z"},{"id":849,"issue_id":"bd-k5q5.9.4","author":"Dicklesworthstone","text":"Dependency intent for LISR-4:\\n- 4.1 defines hard limits (primitive schema).\\n- 4.2 and 4.3 implement constrained proposal + validator/applicator pipeline.\\n- 4.4 provides fail-closed human review for high-risk classes.\\nAI assistance is intentionally downstream and boxed in by policy and deterministic controls.","created_at":"2026-02-08T21:34:44Z"},{"id":860,"issue_id":"bd-k5q5.9.4","author":"Dicklesworthstone","text":"LISR-4 sequencing note:\nModel assistance is constrained by schema, validator, and policy checks before any candidate enters proof gates.\nHigh-risk classes require explicit fail-closed approval.","created_at":"2026-02-08T21:35:28Z"}]}
+{"id":"bd-k5q5.9.3.4","title":"[LISR-3.4] Implement minimal-diff candidate selector and conflict resolver","description":"When multiple deterministic candidates exist, choose the minimal-risk minimal-diff repair and resolve rule conflicts deterministically.","design":"Introduce scoring based on diff size, affected sensitive surfaces, and confidence alignment.","acceptance_criteria":"Selector always returns deterministic winner or explicit no-safe-candidate result.","notes":"This avoids over-editing and keeps repairs constrained to necessary changes.","status":"closed","priority":1,"issue_type":"task","created_at":"2026-02-08T21:32:38.254272971Z","created_by":"ubuntu","updated_at":"2026-02-08T23:21:21.478939261Z","closed_at":"2026-02-08T23:21:21.478844264Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["extensions","lisr","repair","rules","selection"],"dependencies":[{"issue_id":"bd-k5q5.9.3.4","depends_on_id":"bd-k5q5.9.3","type":"parent-child","created_at":"2026-02-08T21:32:38.254272971Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.3.4","depends_on_id":"bd-k5q5.9.3.2","type":"blocks","created_at":"2026-02-08T21:33:00.797572018Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.3.4","depends_on_id":"bd-k5q5.9.3.3","type":"blocks","created_at":"2026-02-08T21:33:01.080281752Z","created_by":"ubuntu"}]}
+{"id":"bd-k5q5.9.4","title":"[LISR-4] Controlled Model-Assisted Repair (Whitelist Only)","description":"Add bounded model-assisted repair proposals for cases deterministic rules cannot resolve, while preserving strict policy controls.","design":"Model outputs are limited to validated primitive patch operations; all proposals are schema-validated and policy-checked before application.","acceptance_criteria":"Model-assisted path cannot bypass policy, cannot introduce unapproved capability expansion, and always emits explainable rejected/accepted decisions.","notes":"This gives coverage for long-tail failures without creating an unconstrained code-generation attack surface.","status":"closed","priority":1,"issue_type":"epic","created_at":"2026-02-08T21:32:26.246357580Z","created_by":"ubuntu","updated_at":"2026-02-08T23:35:40.892006846Z","closed_at":"2026-02-08T23:35:40.891909685Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["ai","extensions","guardrails","lisr","repair"],"dependencies":[{"issue_id":"bd-k5q5.9.4","depends_on_id":"bd-k5q5.9","type":"parent-child","created_at":"2026-02-08T21:32:26.246357580Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.4","depends_on_id":"bd-k5q5.9.1","type":"blocks","created_at":"2026-02-08T21:32:54.297119872Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.4","depends_on_id":"bd-k5q5.9.2","type":"blocks","created_at":"2026-02-08T21:32:55.890049829Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.4","depends_on_id":"bd-k5q5.9.3","type":"blocks","created_at":"2026-02-08T21:32:56.177134804Z","created_by":"ubuntu"}],"comments":[{"id":837,"issue_id":"bd-k5q5.9.4","author":"Dicklesworthstone","text":"Model assistance is scoped to structured primitives only; free-form code generation is explicitly excluded to preserve safety invariants.","created_at":"2026-02-08T21:33:09Z"},{"id":849,"issue_id":"bd-k5q5.9.4","author":"Dicklesworthstone","text":"Dependency intent for LISR-4:\\n- 4.1 defines hard limits (primitive schema).\\n- 4.2 and 4.3 implement constrained proposal + validator/applicator pipeline.\\n- 4.4 provides fail-closed human review for high-risk classes.\\nAI assistance is intentionally downstream and boxed in by policy and deterministic controls.","created_at":"2026-02-08T21:34:44Z"},{"id":860,"issue_id":"bd-k5q5.9.4","author":"Dicklesworthstone","text":"LISR-4 sequencing note:\nModel assistance is constrained by schema, validator, and policy checks before any candidate enters proof gates.\nHigh-risk classes require explicit fail-closed approval.","created_at":"2026-02-08T21:35:28Z"}]}
 {"id":"bd-k5q5.9.4.1","title":"[LISR-4.1] Define model patch primitive whitelist and schema","description":"Define strict primitive patch operations that model proposals may use (for example add/remove/replace AST node classes within policy bounds).","design":"Create machine-checkable schema and semantic constraints for each primitive.","acceptance_criteria":"Any out-of-schema proposal is rejected before application.","notes":"This converts open-ended generation into bounded, verifiable transformations.","status":"closed","priority":0,"issue_type":"task","created_at":"2026-02-08T21:32:38.908401117Z","created_by":"ubuntu","updated_at":"2026-02-08T22:36:38.893600850Z","closed_at":"2026-02-08T22:36:38.893512836Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["ai","extensions","lisr","repair","schema"],"dependencies":[{"issue_id":"bd-k5q5.9.4.1","depends_on_id":"bd-k5q5.9.4","type":"parent-child","created_at":"2026-02-08T21:32:38.908401117Z","created_by":"ubuntu"}]}
-{"id":"bd-k5q5.9.4.2","title":"[LISR-4.2] Implement bounded-context model proposer adapter","description":"Build model adapter that receives only curated context (intent graph, diagnostics, allowed primitives, policy mode) and cannot access secrets.","design":"Standardize prompt contract and deterministic input formatting for reproducibility.","acceptance_criteria":"Adapter output is fully structured and traceable to input context hash.","notes":"Bounded context reduces injection risk and improves reproducibility.","status":"open","priority":1,"issue_type":"task","created_at":"2026-02-08T21:32:39.563839004Z","created_by":"ubuntu","updated_at":"2026-02-08T21:33:06.718427082Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["ai","extensions","lisr","orchestration","repair"],"dependencies":[{"issue_id":"bd-k5q5.9.4.2","depends_on_id":"bd-k5q5.9.2.4","type":"blocks","created_at":"2026-02-08T21:33:06.718381578Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.4.2","depends_on_id":"bd-k5q5.9.4","type":"parent-child","created_at":"2026-02-08T21:32:39.563839004Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.4.2","depends_on_id":"bd-k5q5.9.4.1","type":"blocks","created_at":"2026-02-08T21:33:01.376490535Z","created_by":"ubuntu"}]}
-{"id":"bd-k5q5.9.4.3","title":"[LISR-4.3] Implement proposal validator and constrained applicator","description":"Validate model proposals against primitive schema, policy constraints, and syntactic integrity before generating candidate artifact.","design":"Reject unsupported or policy-violating primitives with precise diagnostics.","acceptance_criteria":"Only validated proposals can enter proof pipeline.","notes":"Validation is the hard barrier preventing unsafe model output from becoming executable artifacts.","status":"open","priority":0,"issue_type":"task","created_at":"2026-02-08T21:32:40.234704823Z","created_by":"ubuntu","updated_at":"2026-02-08T21:33:01.651382996Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["ai","extensions","lisr","repair","validation"],"dependencies":[{"issue_id":"bd-k5q5.9.4.3","depends_on_id":"bd-k5q5.9.4","type":"parent-child","created_at":"2026-02-08T21:32:40.234704823Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.4.3","depends_on_id":"bd-k5q5.9.4.1","type":"blocks","created_at":"2026-02-08T21:33:01.651336459Z","created_by":"ubuntu"}]}
